63: // It is possible to have both subjects and errors returned if some rolebindings couldn't be resolved, but others could be.
64: func (r *SubjectAccessEvaluator) AllowedSubjects(ctx context.Context, requestAttributes authorizer.Attributes) ([]rbacv1.Subject, error) {
65: 	subjects := []rbacv1.Subject{{Kind: rbacv1.GroupKind, APIGroup: rbacv1.GroupName, Name: user.SystemPrivilegedGroup}}
66: 	if len(r.superUser) > 0 {
67: 		subjects = append(subjects, rbacv1.Subject{Kind: rbacv1.UserKind, APIGroup: rbacv1.GroupName, Name: r.superUser})
68: 	}
69: 	errorlist := []error{}
70: 
71: 	if clusterRoleBindings, err := r.clusterRoleBindingLister.ListClusterRoleBindings(ctx); err != nil {
72: 		errorlist = append(errorlist, err)
73: 
74: 	} else {
75: 		for _, clusterRoleBinding := range clusterRoleBindings {
76: 			rules, err := r.roleToRuleMapper.GetRoleReferenceRules(ctx, clusterRoleBinding.RoleRef, "")
77: 			if err != nil {
78: 				// if we have an error, just keep track of it and keep processing.  Since rules are additive,
79: 				// missing a reference is bad, but we can continue with other rolebindings and still have a list
80: 				// that does not contain any invalid values
81: 				errorlist = append(errorlist, err)
82: 			}
83: 			if RulesAllow(requestAttributes, rules...) {
84: 				subjects = append(subjects, clusterRoleBinding.Subjects...)
85: 			}
86: 		}
87: 	}
88: 
89: 	if namespace := requestAttributes.GetNamespace(); len(namespace) > 0 {
90: 		if roleBindings, err := r.roleBindingLister.ListRoleBindings(ctx, namespace); err != nil {
91: 			errorlist = append(errorlist, err)
92: 
93: 		} else {
94: 			for _, roleBinding := range roleBindings {
95: 				rules, err := r.roleToRuleMapper.GetRoleReferenceRules(ctx, roleBinding.RoleRef, namespace)
96: 				if err != nil {
97: 					// if we have an error, just keep track of it and keep processing.  Since rules are additive,
98: 					// missing a reference is bad, but we can continue with other rolebindings and still have a list
99: 					// that does not contain any invalid values
100: 					errorlist = append(errorlist, err)
